## 💡 실전 패턴: 재귀 매크로 작성 가이드

```rust
// [패턴 1] 단순 반복 (항목 개수 세기)
macro_rules! count {
    () => (0);
    ($h:tt $($t:tt)*) => (1 + count!($($t)*));
}

// [패턴 2] 누적 (합계, 연결 등)
macro_rules! sum {
    () => (0);
    ($h:expr, $($t:expr),*) => ($h + sum!($($t),*));
}

// [패턴 3] 변환 (각 항목을 처리)
macro_rules! map {
    () => {};
    ($h:expr, $($t:expr),*) => {
        process($h);
        map!($($t),*);
    };
}

// [패턴 4] 필터링 (조건에 맞는 항목만)
macro_rules! filter {
    () => {};
    ($h:expr, $($t:expr),*) => {
        if is_valid($h) {
            process($h);
        }
        filter!($($t),*);
    };
}

// [패턴 5] 폴딩 (좌측 폴딩)
macro_rules! fold {
    ($acc:expr, ()) => ($acc);
    ($acc:expr, ($h:expr, $($t:expr),*)) => {
        fold!(combine($acc, $h), ($($t),*))
    };
}
```

